#!/usr/bin/env node
/**
 * Build-time defaults generator.
 *
 * Reads SCOPEVEIL_DEFAULT_ENDPOINT from process.env (or .env at the
 * package root if present) and writes src/generated/defaults.ts.
 * The generated file is gitignored — the literal URL never lives in
 * the source tree, only in the published dist artifact.
 *
 * Local dev: put the value in `packages/typescript/.env`.
 * CI: pass via env var (e.g., GitHub Actions secret).
 */

import { readFileSync, writeFileSync, mkdirSync, existsSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const PKG_ROOT = resolve(__dirname, '..');

function readDotEnv(path) {
  if (!existsSync(path)) return {};
  const out = {};
  for (const line of readFileSync(path, 'utf8').split('\n')) {
    const m = line.match(/^\s*([A-Z0-9_]+)\s*=\s*(.*?)\s*$/);
    if (m) out[m[1]] = m[2].replace(/^["']|["']$/g, '');
  }
  return out;
}

const fromFile = readDotEnv(resolve(PKG_ROOT, '.env'));
const endpoint = process.env.SCOPEVEIL_DEFAULT_ENDPOINT
  || fromFile.SCOPEVEIL_DEFAULT_ENDPOINT;
const gatewayEndpoint = process.env.SCOPEVEIL_DEFAULT_GATEWAY_ENDPOINT
  || fromFile.SCOPEVEIL_DEFAULT_GATEWAY_ENDPOINT
  // Sane default — derives from the ingest endpoint by swapping the
  // first label. If both are explicit, that's preferred.
  || (endpoint ? endpoint.replace(/^https?:\/\/[^./]+/, (m) => m.replace(/[^/]+$/, 'gateway')) : null);

if (!endpoint) {
  console.error(
    '[generate-defaults] SCOPEVEIL_DEFAULT_ENDPOINT not set.\n' +
    '  Local dev: copy .env.example to .env and fill in.\n' +
    '  CI: set the env var (or GitHub Actions secret) before build.',
  );
  process.exit(1);
}

const outDir = resolve(PKG_ROOT, 'src/generated');
mkdirSync(outDir, { recursive: true });

const out = `// AUTO-GENERATED by scripts/generate-defaults.mjs at build time.
// Do not edit by hand. Source values come from SCOPEVEIL_DEFAULT_ENDPOINT
// and SCOPEVEIL_DEFAULT_GATEWAY_ENDPOINT (env vars or .env at root).

export const DEFAULT_ENDPOINT = ${JSON.stringify(endpoint)};
export const DEFAULT_GATEWAY_ENDPOINT = ${JSON.stringify(gatewayEndpoint ?? '')};
`;

writeFileSync(resolve(outDir, 'defaults.ts'), out);
console.log(`[generate-defaults] wrote ${outDir}/defaults.ts`);
